  ('elementary-0a2fc18c-moex-00344', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-113-2b7ba743', 'sub-elementary-0a2fc18c-04', NULL, 'single_choice', '甲國生產一磅肉需要8小時，生產一磅馬鈴薯需要5小時；而乙國生產一磅肉需要4小時，生產一磅馬 鈴薯需要10小時，則甲、乙兩國生產一磅肉的機會成本各為何？', '["甲國為0.625磅馬鈴薯、乙國為0.4磅馬鈴薯", "甲國為0.625磅馬鈴薯、乙國為2.5磅馬鈴薯", "甲國為1.6磅馬鈴薯、乙國為0.4磅馬鈴薯", "甲國為1.6磅馬鈴薯、乙國為2.5磅馬鈴薯"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:15+00:00", "source_pdf_sha1": "eec406787878", "answer_pdf_sha1": "1308ad5b4fe4", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "511", "s": "0506", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00345', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-113-2b7ba743', 'sub-elementary-0a2fc18c-04', NULL, 'single_choice', '阿發師和阿水師在職能訓練前，做花捲與包子每分鐘之產量如下表。阿發師接受職能訓練後生產力提高 了，每分鐘可以做出20個花捲或10個包子。職能訓練後，下列何者可以使兩人的總產量最大？ 阿發師 阿水師 花捲 10個 8個 包子 5個 6個', '["阿發師維持做花捲不變", "阿發師維持做包子不變", "阿發師原本做花捲改做包子", "阿發師原本做包子改做花捲"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:15+00:00", "source_pdf_sha1": "eec406787878", "answer_pdf_sha1": "1308ad5b4fe4", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "511", "s": "0506", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00346', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-113-2b7ba743', 'sub-elementary-0a2fc18c-04', NULL, 'single_choice', '某國加入世界貿易組織（WTO）以後，開放外國農產品進口，使其國內農產品價格下跌，對農民生計造 成諸多影響。下列敘述何者錯誤？', '["農民可能因此受害", "專業化趨勢是貿易的必然結果", "如果農業是該國相對劣勢的部門，則貿易將促使生產資源逐步從農業部門轉到相對優勢的部門", "農民的實質購買力會因為農產品跌價而提高，有助於緩和貿易所帶來的所得重分配問題"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:15+00:00", "source_pdf_sha1": "eec406787878", "answer_pdf_sha1": "1308ad5b4fe4", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "511", "s": "0506", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00347', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-113-2b7ba743', 'sub-elementary-0a2fc18c-04', NULL, 'single_choice', '若市場上只有甲、乙二人，其價格需求曲線分別為P＝25－Q與P＝15－Q，其中Q為數量、P為價格。 有關市場需求曲線，下列敘述何者正確？', '["P＝40－2Q", "P＝25－2Q", "當P＝15時發生拗折", "當P＜15時發生拗折"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:15+00:00", "source_pdf_sha1": "eec406787878", "answer_pdf_sha1": "1308ad5b4fe4", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "511", "s": "0506", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00348', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-113-2b7ba743', 'sub-elementary-0a2fc18c-04', NULL, 'single_choice', '有關消費者需求曲線，下列敘述何者錯誤？', '["需求曲線的定義為產品在不同的市場價格之下，消費者購買的產品數量", "消費者需求曲線的推導過程中，廠商的生產成本扮演關鍵的角色", "需求曲線的高度與消費者的願付價格有關", "個別消費者需求曲線的水平加總，可以推導出市場的需求曲線"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:15+00:00", "source_pdf_sha1": "eec406787878", "answer_pdf_sha1": "1308ad5b4fe4", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "511", "s": "0506", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
